import React from "react";
import FeatureDetail from "./FeatureDetail";

const pageData = {
  title: "RASP Protection",
  subtitle: "Runtime Application Self-Protection for application security",
  description: "Protect your applications from within with Runtime Application Self-Protection (RASP). Our solution monitors application behavior in real-time, detects attacks, and takes immediate action to neutralize threats without manual intervention. RASP provides protection even against zero-day vulnerabilities.",
  benefits: [
    "In-app threat detection and prevention at runtime",
    "Real-time application behavior monitoring",
    "Automatic attack neutralization without manual intervention",
    "Zero-day vulnerability protection without signature updates",
    "Minimal performance impact with intelligent throttling"
  ],
  features: [
    { title: "Runtime Protection", description: "Monitors application from the inside during execution" },
    { title: "Attack Prevention", description: "Blocks attacks in real-time before they succeed" },
    { title: "Zero-Day Defense", description: "Protects against unknown vulnerabilities" },
    { title: "Context Awareness", description: "Understands application context to reduce false positives" },
    { title: "Forensic Data", description: "Captures detailed attack information for analysis" }
  ],
  howItWorks: [
    { title: "Agent Deployment", description: "Lightweight agent is deployed within the application" },
    { title: "Behavior Monitoring", description: "Agent monitors all application behavior in real-time" },
    { title: "Threat Detection", description: "Malicious behavior is identified using multiple techniques" },
    { title: "Auto-Response", description: "Attacks are blocked automatically while allowing legitimate traffic" }
  ],
  color: "#f97316",
  icon: "M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z",
  gradient: "from-orange-500 to-red-500"
};

function RASP() {
  return <FeatureDetail {...pageData} />;
}

export default RASP;
